  (8, 'tren-paraiso-maya', 'Tren y Paraíso Maya', 'Riviera Maya, México', 'México', 'Caribe', 'Recorre la Riviera Maya a bordo del moderno Tren Maya. Desde Cancún hasta Tulum, disfruta de cenotes turquesas, zonas arqueológicas y las playas más bellas del Caribe mexicano.', 19898, 19898, 0, 'MXN', '7 noches / 8 días', 7, '/images/packages/trenmaya.jpg', '[]'::jsonb, 'playa', 4.9, 213, '["Vuelo redondo","Pase Tren Maya","Hotel 5 estrellas All-Inclusive","Chichén Itzá","Tour cenotes"]'::jsonb, '["Cancún","Tulum","Chichén Itzá","Cenotes"]'::jsonb, true, true, 2, NULL, 'nacional', 'paquete', 2, NULL, NULL, NULL, NULL, 'https://drive.google.com/file/d/1MYBe8QHdk9yrT7G3wA_rQ76VeyU5aet7/view?usp=drive_link', NULL, NULL, NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-24T19:19:13.359263+00:00', '2026-05-02T22:02:22.256364+00:00'),
  (14, 'vamos-a-colombia', 'Vamos a Colombia', 'Bogotá y Cartagena, Colombia', 'Colombia', 'Sudamérica', 'De Bogotá a Cartagena, Colombia te enamora con su gente cálida, gastronomía colorida, café de altura, arquitectura colonial y el ritmo del Caribe.', 1599, 1999, 20, 'USD', '7 noches / 8 días', 7, '/images/packages/bogota.jpg', '[]'::jsonb, 'cultural', 4.8, 98, '["Vuelo redondo","Hotel boutique Cartagena","City tours","Tour del café","Islas del Rosario"]'::jsonb, '["Cartagena","Bogotá","Café colombiano","Islas del Rosario"]'::jsonb, true, true, 2, NULL, 'internacional', 'paquete', 2, NULL, NULL, NULL, NULL, 'https://drive.google.com/file/d/1AyUr-OcfJKiVEtBvNEngTOzuDQoXNde3/view', NULL, NULL, NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-05-19T21:14:09.319018+00:00', '2026-06-16T14:35:09.729276+00:00'),
  (7, 'barrancas-del-cobre', 'Barrancas del Cobre', 'Chihuahua, México', 'México', 'Norte de México', 'Descubre el Mar de Barrancas en la Sierra Tarahumara. A bordo del legendario Tren El Chepe, recorre uno de los cañones más profundos de México rodeado de naturaleza única.', 19555, 19555, 0, 'MXN', '5 noches / 6 días', 5, '/images/packages/barranchadelcobre.png', '[]'::jsonb, 'aventura', 4.8, 127, '["Vuelo redondo","Tren El Chepe","Hotel en Creel","Guía especializado","Visita a cascadas"]'::jsonb, '["Barranca del Cobre","Creel","Tren El Chepe","Sierra Tarahumara"]'::jsonb, true, true, 1, NULL, 'nacional', 'paquete', 2, NULL, NULL, NULL, NULL, 'https://drive.google.com/file/d/1pSEtONl8ZYNdiqXsEVuR7eQVcJu_M98z/view?usp=sharing', NULL, NULL, NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-24T19:19:13.359263+00:00', '2026-05-08T17:39:16.779093+00:00'),
