-- ---------- blog_posts ----------
INSERT INTO blog_posts (id, title, slug, excerpt, cover_image, content, author, is_published, published_at, created_at, updated_at) OVERRIDING SYSTEM VALUE VALUES
  (1, 'Catedral de Tulancingo de Bravo: joyas arquitectónicas del mundo y por qué vale la pena visitarlas', 'catedral-de-tulancingo-de-bravo-joyas-arquitectonicas-del-mundo-y-por-que-vale-la-pena-visitarlas', 'Descubre cuánto tiene en común la hermosa Catedral de Tulancingo de Bravo con las grandes catedrales del mundo. Un recorrido arquitectónico que inspira tu próximo viaje.', 'https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779126664472-7dhdxa.jpeg', '[{"type":"text","value":"Si te gustan las catedrales, como lo es nuestra bella **Catedral de San Juan Bautista de Tulancingo**, entonces este recorrido visual por las más impresionantes del mundo es para ti. En Sianna Travel creemos que cada gran viaje empieza por apreciar lo que tienes cerca — y desde Tulancingo hay un mundo entero por descubrir."},{"type":"text","value":"## La Catedral de San Juan Bautista, Tulancingo de Bravo\n\nErigida en el siglo XVI durante la evangelización española, la **Catedral de San Juan Bautista de Tulancingo** es uno de los templos más antiguos e importantes del estado de Hidalgo. Su fachada barroca, sus torres simétricas y su interior decorado con retablos dorados testimonian siglos de fe y arte. Tulancingo es una de las primeras ciudades fundadas en el México colonial, lo que le otorga un peso histórico enorme que muchos viajeros pasan por alto."},{"type":"text","value":"## Catedral de Notre-Dame, París, Francia\n\n**Construida:** siglos XII–XIV  \n**Estilo:** Gótico francés  \nConsiderada el símbolo espiritual de Europa, Notre-Dame deslumbra con sus vitrales de colores, sus arbotantes y su roseta central. Tras el incendio de 2019, su restauración ha renovado el interés mundial por el arte gótico.  \n\n**¿Qué comparte con Tulancingo?** Ambas son catedrales que han sobrevivido desafíos históricos y se erigen como centros espirituales de sus comunidades."},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779127034924-oijx3v.jpeg","caption":"Notre-Dame de París, icono del gótico europeo, actualmente en restauración."},{"type":"text","value":"## Basílica de la Sagrada Familia, Barcelona, España\n\n**Arquitecto:** Antoni Gaudí  \n**Estilo:** Modernismo catalán / Neogótico  \nNinguna catedral en construcción atrae más viajeros que la Sagrada Familia. Sus torres orgánicas, sus fachadas narrativas y su interior de luz filtrada la convierten en una experiencia casi mística.  \n\n**¿Qué comparte con Tulancingo?** Las dos son obras de fe que evolucionaron con el tiempo, adaptándose a distintas épocas y estilos artísticos."},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779127020736-byqgz3.jpeg","caption":"La Sagrada Familia de Gaudí sigue en construcción más de 140 años después."},{"type":"text","value":"## Catedral de Saint-Pierre, Ginebra, Suiza\n\n**Construida:** siglos XII–XIII  \n**Estilo:** Gótico / Románico  \nDomina el casco antiguo de Ginebra desde lo alto de la Colina de la Ciudad Vieja. Fue la iglesia desde la que Juan Calvino predicó la Reforma Protestante en el siglo XVI. Su sobriedad interior contrasta con la riqueza histórica que encierra."},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779127010896-a7s13g.webp","caption":"La Catedral de Saint-Pierre en Ginebra, testigo de la Reforma Protestante del siglo XVI."},{"type":"text","value":"## Catedral Metropolitana de la Ciudad de México\n\n**Construida:** 1573–1813  \n**Estilo:** Barroco, Neoclásico  \nLa catedral más grande de América y principal referente del barroco mexicano. Construida sobre el Templo Mayor azteca, combina piedra volcánica gris y arte virreinal. Es prima hermana arquitectónica de nuestra Catedral de San Juan Bautista de Tulancingo — ambas nacieron del mismo impulso evangelizador del siglo XVI en la Nueva España."},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779126996431-qnea1m.jpeg","caption":"La Catedral Metropolitana de la Ciudad de México, la más grande de América Latina."},{"type":"text","value":"## Tabla comparativa\n\n| Catedral | País | Estilo | Siglo de inicio | Altura aprox. |\n|---|---|---|---|---|\n| San Juan Bautista, Tulancingo | México 🇲🇽 | Barroco colonial | XVI | ~30 m |\n| Notre-Dame | Francia 🇫🇷 | Gótico | XII | 69 m |\n| Sagrada Familia | España 🇪🇸 | Modernismo | XIX | 172 m |\n| Saint-Pierre, Ginebra | Suiza 🇨🇭 | Románico / Gótico | XII | 60 m |\n| San Pedro | Vaticano 🇻🇦 | Renacimiento | XVI | 136 m |\n| Catedral CDMX | México 🇲🇽 | Barroco | XVI | 67 m |"},{"type":"text","value":"## ¿Por qué empezar en Tulancingo?\n\nCada una de estas catedrales es la puerta de entrada a una cultura, una historia y un destino de viaje fascinantes. En Tulancingo tenemos la suerte de contar con un patrimonio arquitectónico que nos conecta directamente con esa tradición global.\n\nEn **Sianna Travel** organizamos tours culturales que te llevan desde el corazón de Hidalgo hasta las grandes ciudades del mundo. ¿Te gustaría visitar París, Roma, Ginebra o la Ciudad de México? Escríbenos y diseñamos el itinerario perfecto para ti.\n\n📞 775 265 8513 | 775 752 5171"}]', 'Sianna Travel', true, '2026-05-18T17:57:21.296+00:00', '2026-05-18T17:57:21.860887+00:00', '2026-05-18T22:20:57.240617+00:00'),
  (2, 'Las playas más hermosas para visitar este verano en México y el Caribe', 'las-playas-mas-hermosas-para-visitar-este-verano-en-mexico-y-el-caribe', 'Si quieres playas realmente espectaculares para este verano en el pais, estas son algunas de las más recomendadas por nuestros viajeros. Hay opciones para relajarte, surfear, hacer snorkel o simplemente disfrutar paisajes increíbles.', 'https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779140459022-o91yj3.webp', '[{"type":"text","value":"**Isla Pasión**\n\nUna de las playas más comentadas del año por sus aguas turquesa, arena blanca y ambiente tranquilo. Ideal para descansar y tomar fotos increíbles."},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779140468427-bi2mvz.jpg","caption":""},{"type":"text","value":"**Playa Balandra**\n\nPerfecta si buscas aguas calmadas y paisajes paradisíacos. Muy buena para kayak y paddle board.","caption":""},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779140473557-0nnczq.jpg","caption":""},{"type":"text","value":"**Zicatela**\n\nPara quienes aman el surf y el ambiente relajado. Tiene olas famosas a nivel mundial y atardeceres increíbles.","caption":""},{"type":"image","value":"https://cvtearllxmrdzuatipmo.supabase.co/storage/v1/object/public/package-images/blog/1779140478828-auxwxa.webp","caption":""},{"type":"text","value":"Cada playa tiene algo único que ofrecer, desde paisajes impresionantes hasta comida increíble y actividades para todos los gustos. Visitar una playa en México es desconectarse de la rutina, disfrutar de la naturaleza y crear recuerdos que dan ganas de volver una y otra vez.\n","caption":""},{"type":"text","value":"En **Sianna Travel** organizamos viajes personalizados que te llevan a vivir momentos de calma. ¿Te gustaría visitar alguna de estas playas paradiciacas? Escríbenos y diseñamos una experiencia perfecta para ti.\n\n**Contactanos** \n7757525171 ","caption":""}]', 'siannatravel@gmail.com', true, '2026-05-21T20:49:50.095+00:00', '2026-05-18T21:41:29.966105+00:00', '2026-05-21T20:51:48.18812+00:00')
ON CONFLICT (id) DO NOTHING;

